<?php
namespace App\Domain\GameHome;use App\Domain\Media\MediaAssetType;use App\Models\GameHomeCard;use App\Models\User;use Illuminate\Support\Facades\Log;use Illuminate\Support\Facades\Storage;use Throwable;
final class GameHomeService{private $destinations;public function __construct(GameHomeCardDestinationResolver $destinations){$this->destinations=$destinations;}public function cards(User $user){$cards=GameHomeCard::activeOrdered()->with(['mediaAssets'=>function($q){$q->where('asset_type',MediaAssetType::HOME_CARD_BANNER)->where('is_primary',true)->orderBy('id');}])->get();return$cards->map(function($card)use($user){try{$url=$this->destinations->resolve($card,$user);}catch(Throwable $e){Log::warning('Game home card omitted because its destination is invalid.',['game_home_card_id'=>$card->id,'code'=>$card->code]);return null;}$asset=$card->mediaAssets->first();$banner=$asset&&Storage::disk($asset->disk)->exists($asset->path)?$asset->url():null;return['id'=>(int)$card->id,'name'=>$card->name,'code'=>$card->code,'destination_url'=>$url,'opens_new_tab'=>(bool)$card->opens_new_tab,'banner_url'=>$banner,'uses_fallback'=>$banner===null];})->filter()->values()->all();}}
